import React, { useEffect, useState } from "react";
import { Box, Button, VStack, Heading, Text, Input, HStack, Alert, AlertIcon } from "@chakra-ui/react";
import { useWeb3 } from "./hooks/useWeb3";
import { useToken } from "./hooks/useToken";
import { useCooldown } from "./hooks/useCooldown";
import { ethers } from "ethers";

const App: React.FC = () => {
  const { provider, signer, account, connectWallet } = useWeb3();
  const token = useToken(signer);
  const [balance, setBalance] = useState("0");
  const [cooldown, setCooldown] = useState(0);
  const [alert, setAlert] = useState("");

  const [recipient, setRecipient] = useState("");
  const [amount, setAmount] = useState("");

  useEffect(() => {
    if (!account) return;
    const fetchBalance = async () => {
      const bal = await token.balanceOf(account);
      setBalance(ethers.utils.formatUnits(bal, 18));
      const rem = await token.getRemainingCooldown(account);
      setCooldown(Number(rem));
    };
    fetchBalance();
  }, [account, token]);

  const { formatted: cooldownFormatted } = useCooldown(cooldown);

  const handleRequest = async () => {
    try {
      await token.requestTokens();
      setAlert("Tokens requested successfully!");
      const rem = await token.getRemainingCooldown(account!);
      setCooldown(Number(rem));
    } catch (e: any) {
      setAlert(e?.reason || "Failed to request tokens");
    }
  };

  const handleMint = async () => {
    try {
      await token.mint(account!, ethers.utils.parseUnits(amount || "0", 18));
      setAlert("Minted successfully!");
    } catch (e: any) {
      setAlert(e?.reason || "Mint failed");
    }
  };

  const handleTransfer = async () => {
    try {
      await token.transfer(recipient, ethers.utils.parseUnits(amount || "0", 18));
      setAlert("Transfer successful!");
    } catch (e: any) {
      setAlert(e?.reason || "Transfer failed");
    }
  };

  return (
    <Box p={10}>
      <VStack spacing={4}>
        <Heading>WEB3CXIV Token Dashboard</Heading>

        {!account && <Button onClick={connectWallet}>Connect Wallet</Button>}

        {account && (
          <>
            <Text>Account: {account}</Text>
            <Text>Balance: {balance} CXIV</Text>
            {cooldown > 0 ? (
              <Text>Faucet cooldown: {cooldownFormatted}</Text>
            ) : (
              <Button onClick={handleRequest}>Request Tokens</Button>
            )}

            <HStack>
              <Input
                placeholder="Recipient Address"
                value={recipient}
                onChange={(e) => setRecipient(e.target.value)}
              />
              <Input
                placeholder="Amount"
                value={amount}
                onChange={(e) => setAmount(e.target.value)}
              />
              <Button onClick={handleTransfer}>Transfer</Button>
            </HStack>

            <HStack>
              <Input
                placeholder="Mint Amount"
                value={amount}
                onChange={(e) => setAmount(e.target.value)}
              />
              <Button onClick={handleMint}>Mint</Button>
            </HStack>

            {alert && (
              <Alert status="info">
                <AlertIcon />
                {alert}
              </Alert>
            )}
          </>
        )}
      </VStack>
    </Box>
  );
};

export default App;
